spec:
// SSL setup contract for deployment tasks
// Files: nginx/ssl.conf, scripts/setup-ssl.sh, scripts/setup-ssl-selfsigned.sh, scripts/sync-letsencrypt-certs.sh, docs/SSL_SETUP.md

// Runtime expectations when HTTPS is enabled:
// - cert mount path inside nginx: /etc/nginx/certs
// - required files: fullchain.pem, privkey.pem, dhparam.pem
// - ACME challenge webroot inside nginx: /var/www/certbot

// nginx/ssl.conf behavior:
// - HTTP :80 server keeps GET /health returning 200 OK
// - HTTP serves /.well-known/acme-challenge/* from /var/www/certbot
// - all other HTTP requests redirect to https://$host$request_uri
// - HTTPS :443 server serves the SPA with the same cache and security-header policy as nginx/nginx.conf
// - TLS settings: TLSv1.2 + TLSv1.3, Mozilla-compatible intermediate cipher list, explicit curves/session settings

// Scripts:
// - scripts/setup-ssl.sh <domain> <email> [acme-webroot]
//   installs certbot (snap-preferred, apt fallback), runs certonly --webroot, syncs files into ./certs, writes /etc/cron.d/worktracker-certbot-renew, and validates renew --dry-run
// - scripts/setup-ssl-selfsigned.sh [common-name]
//   writes ./certs/fullchain.pem, ./certs/privkey.pem, ./certs/dhparam.pem for local/dev use
// - scripts/sync-letsencrypt-certs.sh <domain>
//   copies /etc/letsencrypt/live/<domain>/{fullchain.pem,privkey.pem} into ./certs and creates dhparam.pem if missing

// Security note:
// - repo .gitignore excludes certs/ so generated private keys are not committed
